/**
 * Complete EU5 country definitions from the Paradox wiki.
 * 2,296 countries with tag, name, rank, government, culture, religion, map color, etc.
 * Source: https://eu5.paradoxwikis.com/Country/List/
 */

// =============================================================================
// Types
// =============================================================================

export interface CountryDef {
  readonly tag: string;
  readonly name: string;
  readonly rank: "County" | "Duchy" | "Kingdom" | "Empire";
  readonly type: "pop" | "location" | "army" | "building";
  readonly government: "monarchy" | "republic" | "theocracy" | "tribe" | "steppe_horde";
  readonly culture: string;
  readonly religion: string;
  readonly mapColor: readonly [number, number, number];
  readonly capital: string;
  readonly techLevel: number;
  readonly difficulty: number;
  readonly courtLanguage: string;
  readonly dynasty: string;
  readonly acceptedCultures: readonly string[];
  readonly toleratedCultures: readonly string[];
  readonly liturgicalLanguage: string;
  readonly isHistoric: boolean;
  readonly formableLevel: number;
  readonly revolt: boolean;
}

// =============================================================================
// Helpers
// =============================================================================

const clamp = (n: number): number => Math.min(255, Math.max(0, n));

const parseRgb = (s: string): readonly [number, number, number] => {
  const m = s.match(/rgb\((\d+),(\d+),(\d+)\)/);
  return m ? [clamp(+m[1]), clamp(+m[2]), clamp(+m[3])] as const : [128, 128, 128] as const;
};

const splitList = (s: string): readonly string[] =>
  s === "" ? [] : s.split(";").map(x => x.trim());

