/** All EU5 country definitions, keyed by tag. */
export const COUNTRY_DEFS: Readonly<Record<string, CountryDef>> = Object.fromEntries(
  RAW.map(([tag, name, rank, type, government, culture, religion, mapColor, capital, techLevel, difficulty, courtLanguage, dynasty, accepted, tolerated, liturgical, isHistoric, formableLevel, revolt]) => [
    tag,
    {
      tag, name,
      rank: rank as CountryDef["rank"],
      type: type as CountryDef["type"],
      government: government as CountryDef["government"],
      culture, religion,
      mapColor: parseRgb(mapColor),
      capital, techLevel, difficulty, courtLanguage, dynasty,
      acceptedCultures: splitList(accepted),
      toleratedCultures: splitList(tolerated),
      liturgicalLanguage: liturgical,
      isHistoric: isHistoric === 1,
      formableLevel: formableLevel,
      revolt: revolt === 1,
    } satisfies CountryDef,
  ]),
);

/** Look up a country definition by tag. */
export const countryDef = (tag: string): CountryDef | undefined =>
  COUNTRY_DEFS[tag];

/** Get the display name for a tag, or empty string if unknown. */
export const wikiName = (tag: string): string =>
  COUNTRY_DEFS[tag]?.name ?? "";
